from langgraph.checkpoint.memory import MemorySaver

app = graph.compile(checkpointer=MemorySaver())
config = {"configurable": {"thread_id": "stream-1"}}

for state in app.stream(initial_state, config=config, stream_mode="values"):
    # state is the full state dict after the most recently completed node
    last_msg = state["messages"][-1] if state.get("messages") else None
    if last_msg:
        print(f"  [{last_msg.__class__.__name__}] {str(last_msg.content)[:80]}")

for event in app.stream(initial_state, stream_mode="debug"):
    evt_type = event.get("type")
    if evt_type == "task":
        print(f"Task started: node={event['payload']['name']}")
    elif evt_type == "task_result":
        node = event["payload"]["name"]
        print(f"Task done:    node={node} keys={list(event['payload']['result'][0][1].keys())}")
    elif evt_type == "checkpoint":
        print(f"Checkpoint saved at step {event['payload']['step']}")

for mode, data in app.stream(
    initial_state,
    stream_mode=["updates", "debug"],
):
    if mode == "updates":
        node, delta = next(iter(data.items()))
        print(f"UPDATE [{node}]: {list(delta.keys())}")
    elif mode == "debug":
        evt_type = data.get("type")
        if evt_type == "checkpoint":
            print(f"DEBUG: checkpoint at step {data['payload']['step']}")

# Include subgraph node events in the stream
for step in app.stream(
    initial_state,
    stream_mode="updates",
    subgraphs=True,
):
    # step is a tuple: (namespace_tuple, delta_dict)
    namespace, delta = step
    node = list(delta.keys())[0]
    if namespace:
        print(f"  [subgraph:{namespace[-1]}] {node}: {list(delta[node].keys())}")
    else:
        print(f"[outer] {node}: {list(delta[node].keys())}")

import pytest
from langchain_core.messages import AIMessage, HumanMessage
from langgraph.checkpoint.memory import MemorySaver
from unittest.mock import MagicMock

def make_fake_llm(responses: list[str]):
    call_count = [0]
    mock = MagicMock()
    def invoke(messages, **kwargs):
        idx = min(call_count[0], len(responses) - 1)
        call_count[0] += 1
        return AIMessage(content=responses[idx])
    mock.invoke = invoke
    mock.bind_tools = lambda tools: mock
    return mock

@pytest.fixture
def streaming_app():
    fake = make_fake_llm(["I will search.", "The answer is Paris."])
    # Patch the LLM in your agent node
    return build_graph(llm=fake).compile(checkpointer=MemorySaver())

def test_stream_updates_contains_agent_node(streaming_app):
    config = {"configurable": {"thread_id": "test-stream"}}
    steps = list(streaming_app.stream(
        {"messages": [HumanMessage(content="Capital of France?")]},
        config=config,
        stream_mode="updates",
    ))
    nodes_fired = [list(s.keys())[0] for s in steps]
    assert "agent" in nodes_fired

def test_final_message_in_last_update(streaming_app):
    config = {"configurable": {"thread_id": "test-stream-2"}}
    last = None
    for step in streaming_app.stream(
        {"messages": [HumanMessage(content="Capital of France?")]},
        config=config,
        stream_mode="updates",
    ):
        last = step
    assert last is not None
    node, delta = next(iter(last.items()))
    assert "messages" in delta
